export function getPGStats(pgId) {
  const pg = ownerPGs.find(p => p.id === pgId);
  if (!pg) return { totalBeds: 0, occupiedBeds: 0, vacantBeds: 0, overdueBeds: 0 };
  
  const allBeds = pg.rooms.flatMap(r => r.beds);
  return {
    totalBeds: allBeds.length,
    occupiedBeds: allBeds.filter(b => b.status === 'occupied').length,
    vacantBeds: allBeds.filter(b => b.status === 'vacant').length,
    overdueBeds: allBeds.filter(b => b.status === 'overdue').length,
  };
}

export function getOverallStats() {
  const allBeds = ownerPGs.flatMap(pg => pg.rooms.flatMap(r => r.beds));
  const totalBeds = allBeds.length;
  const occupiedBeds = allBeds.filter(b => b.status === 'occupied' || b.status === 'overdue').length;
  
  const collectedRent = ownerTenants
    .filter(t => t.rentStatus === 'paid')
    .reduce((sum, t) => sum + t.monthlyRent, 0);
  
  const overdueRent = ownerTenants
    .filter(t => t.rentStatus === 'overdue')
    .reduce((sum, t) => sum + t.monthlyRent, 0);
  
  return {
    totalBeds,
    occupiedBeds,
    vacantBeds: totalBeds - occupiedBeds,
    collectedRent,
    overdueRent,
  };
}
